// ─── Parse LinkedIn Job Alert Email ───────────────────────────────────────
// Extracts job listings from LinkedIn job alert HTML emails.
// LinkedIn sends alerts from jobalerts-noreply@linkedin.com
// with job cards containing title, company, location, and apply URL.

const items = [];

for (const item of $input.all()) {
  const html    = item.json.html || item.json.body || '';
  const subject = item.json.subject || '';
  const msgId   = item.json.id || item.json.messageId || String(Date.now());
  const recvAt  = item.json.date || new Date().toISOString();

  const jobs = [];
  const seen = new Set();

  // ── Strategy 1: Extract from HTML anchor tags ──────────────────────────
  // LinkedIn job URLs look like:
  //   https://www.linkedin.com/comm/jobs/view/1234567890?...
  //   https://www.linkedin.com/jobs/view/1234567890?...
  const linkRe = /href=["'](https:\/\/www\.linkedin\.com\/(?:comm\/)?jobs\/view\/(\d+)[^"']*)["'][^>]*>([\s\S]*?)<\/a>/gi;
  let m;

  while ((m = linkRe.exec(html)) !== null) {
    const rawUrl = m[1];
    const jobId  = m[2];
    const title  = m[3].replace(/<[^>]+>/g, '').replace(/\s+/g, ' ').trim();

    // Skip nav/footer links and duplicates
    if (!title || title.length < 3 || seen.has(jobId)) continue;
    seen.add(jobId);

    // Build a clean URL without tracking params
    const cleanUrl = `https://www.linkedin.com/jobs/view/${jobId}/`;

    // Try to extract company & location from nearby HTML context
    const cardStart  = Math.max(0, m.index - 800);
    const cardEnd    = Math.min(html.length, m.index + 800);
    const cardSlice  = html.slice(cardStart, cardEnd);
    const plainCard  = cardSlice.replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ');

    // Heuristic: company is the first non-empty token after the job title
    const afterTitle = plainCard.slice(plainCard.indexOf(title) + title.length);
    const tokens = afterTitle.split('·').map(t => t.trim()).filter(Boolean);
    const company  = tokens[0] || '';
    const location = tokens[1] || '';

    jobs.push({
      title,
      company,
      location,
      url: cleanUrl,
      raw: { source: 'LinkedIn Email', originalUrl: rawUrl, subject }
    });
  }

  // ── Strategy 2: Fallback to plain-text URL extraction ─────────────────
  if (jobs.length === 0) {
    const text   = item.json.text || item.json.snippet || '';
    const urlRe  = /https:\/\/www\.linkedin\.com\/(?:comm\/)?jobs\/view\/(\d+)/g;
    let urlMatch;
    while ((urlMatch = urlRe.exec(text)) !== null) {
      const jobId = urlMatch[1];
      if (seen.has(jobId)) continue;
      seen.add(jobId);
      jobs.push({
        title:    subject.replace(/^\d+\+? (?:new )?jobs? (?:for|matching) /i, '').trim(),
        company:  '',
        location: '',
        url:      `https://www.linkedin.com/jobs/view/${jobId}/`,
        raw:      { source: 'LinkedIn Email (text fallback)', subject }
      });
    }
  }

  items.push({
    json: {
      source:   'linkedin_email',
      runId:    `${recvAt}_${msgId}`,
      email: {
        emailId:    msgId,
        receivedAt: recvAt,
        subject:    subject,
        snippet:    item.json.snippet || subject.slice(0, 200)
      },
      jobs,
      _jobCount: jobs.length
    }
  });
}

return items;

// Log emails that contained no extractable jobs
for (const item of $input.all()) {
  console.log(`[SKIP] No jobs found in: "${item.json.email?.subject}"`);
}
return $input.all();

// Log the result from the backend for monitoring
for (const item of $input.all()) {
  const res = item.json;
  console.log(`[INGEST] emailId=${res.emailId} inserted=${res.inserted} updated=${res.updated} skipped=${res.skipped} alreadyProcessed=${res.alreadyProcessed}`);
}
return $input.all();
